parameters.jsCode:
const inputItems = $input.all();
const emails = $("Fetch External Emails").all();
const results = [];

for (let i = 0; i < inputItems.length; i++) {
  const email = emails[i] ? emails[i].json : {};

  let classification = {};
  try {
    const claudeText = inputItems[i].json.content[0].text;
    const jsonMatch = claudeText.match(/{[\s\S]*}/);
    if (jsonMatch) {
      classification = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    console.log("Failed to parse Claude response for item " + i + ": " + e.message);
  }

  classification = Object.assign({
    topic: "Other",
    urgency: "normal",
    status: "inbox",
    summary: email.subject || "",
    key_points: [],
    action_items: [],
    requires_response: false,
    is_vip: false
  }, classification);

  let receivedAt;
  try {
    const d = email.date ? new Date(email.date) : new Date();
    receivedAt = isNaN(d.getTime()) ? new Date().toISOString() : d.toISOString();
  } catch (e) {
    receivedAt = new Date().toISOString();
  }

  let senderEmail = "";
  let senderName = "";
  if (email.from && typeof email.from === "object") {
    if (Array.isArray(email.from.value) && email.from.value.length) {
      senderEmail = email.from.value[0].address || "";
      senderName = email.from.value[0].name || "";
    } else if (email.from.text) {
      senderEmail = email.from.text;
    }
  } else if (typeof email.from === "string") {
    senderEmail = email.from;
  }

  let recipient = "";
  if (email.to && typeof email.to === "object") {
    recipient = email.to.text || "";
  } else if (typeof email.to === "string") {
    recipient = email.to;
  }

  results.push({
    json: {
      gmail_id: email.id,
      thread_id: email.threadId,
      sender: { email: senderEmail, name: senderName },
      recipient: recipient,
      subject: email.subject || "",
      body_text: email.text || "",
      snippet: email.snippet || "",
      received_at: receivedAt,
      attachments: [],
      classification: classification
    }
  });
}

return results;
